    fn __token_to_integer<
        'a,
    >(
        __token: &crate::cmd_parse::lexer::Tok,
        _: core::marker::PhantomData<(&'a ())>,
    ) -> Option<usize>
    {
        #[warn(unused_variables)]
        match __token {
            lexer::Tok::Newline if true => Some(0),
            lexer::Tok::Semicolon if true => Some(1),
            lexer::Tok::LeftBrace if true => Some(2),
            lexer::Tok::RightBrace if true => Some(3),
            lexer::Tok::Hidden if true => Some(4),
            lexer::Tok::If if true => Some(5),
            lexer::Tok::Elif if true => Some(6),
            lexer::Tok::Endif if true => Some(7),
            lexer::Tok::Else if true => Some(8),
            lexer::Tok::Error if true => Some(9),
            lexer::Tok::Format(_) if true => Some(10),
            lexer::Tok::Token(_) if true => Some(11),
            lexer::Tok::Equals(_) if true => Some(12),
            _ => None,
        }
    }
